import { Container } from "@gunjo/ui";
import { CarePlanClient } from "./CarePlanClient";
import { officeName, myName, todayLabel } from "./data";

export const metadata = {
  title: "ケアプラン作成・管理 | みなと居宅介護支援センター",
  description:
    "ケアマネジャー（介護支援専門員）向けの居宅サービス計画（ケアプラン）作成・モニタリング・交付管理画面",
};

export default function CarePlanPage() {
  return (
    <Container size="2xl" className="py-6 sm:py-8">
      <header className="mb-6 space-y-1.5">
        <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
          <span>{officeName}</span>
          <span aria-hidden>·</span>
          <span className="tabular-nums">{todayLabel}</span>
        </div>
        <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
          ケアプラン作成・管理
        </h1>
        <p className="text-sm text-muted-foreground">
          居宅サービス計画 ― {myName}
        </p>
      </header>

      <CarePlanClient />
    </Container>
  );
}

"use client";

import * as React from "react";
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
  CheckList,
  DataTable,
  EmptyState,
  MetadataList,
  PersonCell,
  ScheduleGrid,
  SignedRecord,
  Separator,
  Statistic,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Tag,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  ApprovalSteps,
  RadioGroup,
  RadioGroupItem,
  Textarea,
  type ColumnDef,
} from "@gunjo/ui";
import {
  IconUsers,
  IconCalendarStats,
  IconClipboardCheck,
  IconAlertTriangle,
  IconPencil,
  IconChevronLeft,
  IconChevronRight,
  IconHome2,
  IconStethoscope,
  IconArmchair2,
  IconBuildingHospital,
} from "@tabler/icons-react";

import {
  plans,
  weeklyTimes,
  weeklyDays,
  myName,
  myId,
  statusTone,
  serviceKindTone,
  achievementTone,
  careLevelOrder,
  daysUntil,
  formatJpDate,
  type CarePlan,
  type PlanStatus,
  type GoalAchievement,
  type ServiceKind,
  type ServiceProvider,
  type WeeklySlot,
} from "./data";
import type { SignedRecordValue, ScheduleCell, ScheduleCellTone } from "@gunjo/ui";

// サービス種別 → アイコン（PersonCell の avatar fallback / 凡例に使う）
const KIND_ICON: Record<ServiceKind, React.ComponentType<{ className?: string }>> = {
  訪問介護: IconHome2,
  通所介護: IconArmchair2,
  通所リハ: IconArmchair2,
  訪問看護: IconStethoscope,
  福祉用具貸与: IconBuildingHospital,
  短期入所生活介護: IconBuildingHospital,
  訪問入浴: IconHome2,
};

const KIND_CELL_TONE: Record<ServiceKind, ScheduleCellTone> = {
  訪問介護: "info",
  通所介護: "success",
  通所リハ: "success",
  訪問看護: "warning",
  福祉用具貸与: "muted",
  短期入所生活介護: "muted",
  訪問入浴: "primary",
};

// ───────────────────────── 利用者一覧 (DataTable) ─────────────────────────

function CaseloadTable({ onOpen }: { onOpen: (id: string) => void }) {
  const columns = React.useMemo<ColumnDef<CarePlan>[]>(
    () => [
      {
        accessorKey: "name",
        header: "利用者",
        cell: ({ row }) => {
          const p = row.original;
          return (
            <PersonCell
              size="sm"
              name={p.name}
              secondary={`${p.nameKana}・${p.age}歳 ${p.sex}`}
              avatarClassName="bg-secondary text-secondary-foreground"
            />
          );
        },
      },
      {
        accessorKey: "careLevel",
        header: "要介護度",
        size: 96,
        sortingFn: (a, b) =>
          careLevelOrder[a.original.careLevel] - careLevelOrder[b.original.careLevel],
        cell: ({ row }) => (
          <Badge variant="outline">{row.original.careLevel}</Badge>
        ),
      },
      {
        accessorKey: "status",
        header: "計画状態",
        size: 96,
        cell: ({ row }) => {
          const s = row.original.status as PlanStatus;
          return <Badge variant={statusTone[s]}>{s}</Badge>;
        },
      },
      {
        accessorKey: "certExpiry",
        header: "認定有効期限",
        size: 132,
        cell: ({ row }) => {
          const left = daysUntil(row.original.certExpiry);
          const soon = left <= 45;
          return (
            <div className="flex flex-col">
              <span className="tabular-nums">{formatJpDate(row.original.certExpiry)}</span>
              <span
                className={
                  soon ? "text-xs font-medium text-warning-strong" : "text-xs text-muted-foreground"
                }
              >
                残り{left}日{soon ? "・更新間近" : ""}
              </span>
            </div>
          );
        },
      },
      {
        accessorKey: "nextMonitoring",
        header: "次回モニタリング",
        size: 132,
        cell: ({ row }) => {
          const left = daysUntil(row.original.nextMonitoring);
          const overdueOrSoon = left <= 3;
          return (
            <div className="flex flex-col">
              <span className="tabular-nums">{formatJpDate(row.original.nextMonitoring)}</span>
              <span
                className={
                  overdueOrSoon
                    ? "text-xs font-medium text-destructive"
                    : "text-xs text-muted-foreground"
                }
              >
                {left < 0 ? `${-left}日超過` : `あと${left}日`}
              </span>
            </div>
          );
        },
      },
      {
        accessorKey: "careManager",
        header: "担当ケアマネ",
        size: 132,
        cell: ({ row }) => (
          <span className="text-sm text-muted-foreground">{row.original.careManager}</span>
        ),
      },
      {
        id: "open",
        header: "",
        size: 88,
        cell: () => (
          <span className="inline-flex items-center gap-1 text-xs font-medium text-muted-foreground">
            開く
            <IconChevronRight className="h-3.5 w-3.5" aria-hidden />
          </span>
        ),
      },
    ],
    []
  );

  return (
    <DataTable
      columns={columns}
      data={plans}
      pageSize={10}
      onRowClick={(p) => onOpen(p.id)}
      filter={{ columnId: "name", placeholder: "利用者名で絞り込み…" }}
      labels={{
        filterPlaceholder: "利用者名で絞り込み…",
        noResults: "該当する利用者がいません。",
        paginationSummary: (from, to, total) => `${total}件中 ${from}–${to}件`,
        pageSummary: (cur, tot) => `${cur} / ${tot} ページ`,
        rowsPerPage: "表示件数",
        firstPage: "最初のページ",
        previous: "前へ",
        next: "次へ",
        lastPage: "最後のページ",
      }}
      renderCard={(p) => (
        <div className="flex flex-col gap-2">
          <div className="flex items-start justify-between gap-2">
            <PersonCell
              size="sm"
              name={p.name}
              secondary={`${p.age}歳 ${p.sex}・${p.careLevel}`}
            />
            <Badge variant={statusTone[p.status]}>{p.status}</Badge>
          </div>
          <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-muted-foreground">
            <span>認定期限 {formatJpDate(p.certExpiry)}</span>
            <span>次回モニタ {formatJpDate(p.nextMonitoring)}</span>
          </div>
        </div>
      )}
    />
  );
}

// ───────────────────────── 事業所担当者 (PersonCell) ─────────────────────────

function ProviderCell({ provider }: { provider: ServiceProvider }) {
  const Icon = KIND_ICON[provider.kind];
  return (
    <PersonCell
      size="sm"
      name={provider.contact}
      secondary={`${provider.office}`}
      tertiary={provider.role}
      avatar={{ fallback: <Icon className="h-4 w-4" /> }}
      avatarClassName="bg-muted text-muted-foreground"
      trailing={<Badge variant={serviceKindTone[provider.kind]}>{provider.kind}</Badge>}
    />
  );
}

// ───────────────────────── 第1表 + 第2表 (計画書) ─────────────────────────

function PlanSheets({ plan }: { plan: CarePlan }) {
  const providerById = React.useMemo(
    () => new Map(plan.providers.map((p) => [p.id, p])),
    [plan.providers]
  );

  return (
    <div className="flex flex-col gap-6">
      {/* 第1表：意向・方針 */}
      <Card>
        <CardHeader>
          <CardTitle as="h3">第1表　利用者・家族の意向と総合的な援助方針</CardTitle>
          <CardDescription>居宅サービス計画書（1）</CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          <div>
            <p className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              利用者の生活に対する意向
            </p>
            <p className="text-sm leading-relaxed text-foreground">{plan.intentionUser}</p>
          </div>
          <div>
            <p className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              家族の意向
            </p>
            <p className="text-sm leading-relaxed text-foreground">{plan.intentionFamily}</p>
          </div>
          <Separator />
          <div>
            <p className="mb-1 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              総合的な援助の方針
            </p>
            <p className="text-sm leading-relaxed text-foreground">{plan.policy}</p>
          </div>
        </CardContent>
      </Card>

      {/* 第2表：課題→目標→サービス */}
      <Card>
        <CardHeader>
          <CardTitle as="h3">第2表　課題（ニーズ）・目標・サービス内容</CardTitle>
          <CardDescription>
            生活全般の解決すべき課題ごとに、長期目標／短期目標／援助内容を整理します。
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-5">
          {plan.needs.map((need, i) => (
            <div key={need.id} className="rounded-lg border border-border bg-muted/20 p-4">
              <div className="mb-3 flex items-start gap-2">
                <span
                  aria-hidden
                  className="mt-0.5 inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-foreground text-xs font-bold text-background"
                >
                  {i + 1}
                </span>
                <div className="min-w-0">
                  <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                    課題（ニーズ）
                  </p>
                  <p className="text-sm font-medium leading-relaxed text-foreground">
                    {need.need}
                  </p>
                </div>
              </div>

              <MetadataList
                layout="horizontal"
                items={[
                  {
                    label: "長期目標",
                    value: need.longTermGoal,
                    description: `期間 ${need.longTermPeriod}`,
                  },
                  {
                    label: "短期目標",
                    value: need.shortTermGoal,
                    description: `期間 ${need.shortTermPeriod}`,
                  },
                ]}
              />

              <p className="mb-2 mt-4 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                援助内容（サービス）
              </p>
              <ul className="flex flex-col gap-2">
                {need.services.map((s, si) => {
                  const provider = providerById.get(s.providerId);
                  return (
                    <li
                      key={si}
                      className="flex flex-col gap-1.5 rounded-md border border-border bg-card p-3 sm:flex-row sm:items-start sm:justify-between"
                    >
                      <div className="min-w-0">
                        <div className="flex flex-wrap items-center gap-2">
                          <Badge variant={serviceKindTone[s.kind]}>{s.kind}</Badge>
                          <span className="text-sm font-medium text-foreground">
                            {s.description}
                          </span>
                        </div>
                        {provider ? (
                          <p className="mt-1 text-xs text-muted-foreground">
                            {provider.office}（{provider.contact}）
                          </p>
                        ) : null}
                      </div>
                      <div className="flex shrink-0 flex-wrap gap-1.5">
                        <Tag variant="outline" size="sm">
                          {s.frequency}
                        </Tag>
                        <Tag variant="outline" size="sm">
                          {s.period}
                        </Tag>
                      </div>
                    </li>
                  );
                })}
              </ul>
            </div>
          ))}
        </CardContent>
      </Card>

      {/* 担当事業所一覧 */}
      <Card>
        <CardHeader>
          <CardTitle as="h3">サービス提供事業所・担当者</CardTitle>
          <CardDescription>利用者を支えるサービスチームの担当窓口。</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
            {plan.providers.map((p) => (
              <div key={p.id} className="rounded-md border border-border bg-card p-3">
                <ProviderCell provider={p} />
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

// ───────────────────────── 第3表 (週間サービス計画) ─────────────────────────

function WeeklyPlan({ plan }: { plan: CarePlan }) {
  const providerById = React.useMemo(
    () => new Map(plan.providers.map((p) => [p.id, p])),
    [plan.providers]
  );

  const rows = weeklyTimes.map((t) => ({ id: t.id, label: t.label, sublabel: t.sub }));
  const columns = weeklyDays.map((d) => ({ id: d, label: d }));

  const cells: ScheduleCell[] = plan.weekly.map((slot: WeeklySlot) => {
    const provider = providerById.get(slot.providerId);
    return {
      rowId: slot.timeId,
      colId: slot.day,
      tone: KIND_CELL_TONE[slot.kind],
      description: `${slot.kind} ${slot.service}${provider ? ` ${provider.office}` : ""}`,
      content: (
        <div className="flex flex-col gap-0.5">
          <span className="text-xs font-semibold leading-tight">{slot.service}</span>
          <span className="text-[10px] leading-tight text-muted-foreground">
            {provider?.office ?? slot.kind}
          </span>
        </div>
      ),
    };
  });

  if (plan.weekly.length === 0) {
    return (
      <EmptyState
        headingLevel={3}
        icon={<IconCalendarStats className="h-6 w-6" aria-hidden />}
        title="週間サービス計画は未作成です"
        description="第2表のサービス内容を確定すると、週間計画に配置できます。"
      />
    );
  }

  return (
    <div className="flex flex-col gap-3">
      <ScheduleGrid
        label={`${plan.name}様 週間サービス計画`}
        cornerLabel="時間帯"
        rows={rows}
        columns={columns}
        cells={cells}
        minColumnWidth={92}
        rowHeaderWidth={64}
      />
      <div className="flex flex-wrap items-center gap-2">
        <span className="text-xs text-muted-foreground">凡例:</span>
        {(["訪問介護", "通所介護", "訪問看護", "福祉用具貸与"] as ServiceKind[]).map((k) => (
          <Badge key={k} variant={serviceKindTone[k]}>
            {k}
          </Badge>
        ))}
      </div>
    </div>
  );
}

// ───────────────────────── モニタリング ─────────────────────────

const ACHIEVEMENT_OPTIONS: GoalAchievement[] = ["達成", "一部達成", "未達"];

function Monitoring({ plan }: { plan: CarePlan }) {
  // ローカルに評価を保持（モニタリング記録の編集を体験させる）
  const [evals, setEvals] = React.useState<
    Record<string, { achievement: GoalAchievement; note: string }>
  >(() =>
    Object.fromEntries(
      plan.needs.map((n) => [
        n.id,
        { achievement: n.achievement, note: n.monitoringNote ?? "" },
      ])
    )
  );

  if (plan.needs.length === 0) {
    return (
      <EmptyState
        headingLevel={3}
        icon={<IconClipboardCheck className="h-6 w-6" aria-hidden />}
        title="評価対象の目標がありません"
        description="計画書の短期目標が設定されると、ここで達成状況を評価できます。"
      />
    );
  }

  return (
    <div className="flex flex-col gap-4">
      <p className="text-sm text-muted-foreground">
        各短期目標の達成状況を評価し、所見を記録します。次回モニタリング予定日:{" "}
        <span className="font-medium text-foreground">{formatJpDate(plan.nextMonitoring)}</span>
      </p>
      {plan.needs.map((need, i) => {
        const cur = evals[need.id];
        return (
          <Card key={need.id}>
            <CardHeader>
              <CardTitle as="h3" className="text-base">
                目標{i + 1}　{need.shortTermGoal}
              </CardTitle>
              <CardDescription>課題: {need.need}</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-3">
              <div>
                <p
                  id={`eval-${need.id}`}
                  className="mb-1.5 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
                >
                  達成状況
                </p>
                <RadioGroup
                  aria-labelledby={`eval-${need.id}`}
                  className="flex flex-row flex-wrap gap-4"
                  value={cur.achievement === "未評価" ? undefined : cur.achievement}
                  onValueChange={(v) =>
                    setEvals((prev) => ({
                      ...prev,
                      [need.id]: { ...prev[need.id], achievement: v as GoalAchievement },
                    }))
                  }
                >
                  {ACHIEVEMENT_OPTIONS.map((opt) => (
                    <RadioGroupItem key={opt} value={opt} label={opt} />
                  ))}
                </RadioGroup>
                <div className="mt-2">
                  <Badge variant={achievementTone[cur.achievement]}>
                    現在の評価: {cur.achievement}
                  </Badge>
                </div>
              </div>
              <Textarea
                label="所見・経過"
                rows={3}
                value={cur.note}
                placeholder="目標に対する達成度、生活の変化、今後の方針などを記録します。"
                onChange={(e) =>
                  setEvals((prev) => ({
                    ...prev,
                    [need.id]: { ...prev[need.id], note: e.target.value },
                  }))
                }
              />
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

// ───────────────────────── サービス担当者会議 ─────────────────────────

function Conference({ plan }: { plan: CarePlan }) {
  const { conference } = plan;
  if (!conference.date) {
    return (
      <EmptyState
        headingLevel={3}
        icon={<IconUsers className="h-6 w-6" aria-hidden />}
        title="サービス担当者会議の記録がありません"
        description="会議を開催したら、出席者と検討事項を記録します。"
      />
    );
  }

  const attendedCount = conference.attendees.filter((a) => a.attended).length;

  return (
    <div className="flex flex-col gap-6">
      <Card>
        <CardHeader>
          <CardTitle as="h3">サービス担当者会議</CardTitle>
          <CardDescription>
            開催日 {formatJpDate(conference.date)}・{conference.location}
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          <div>
            <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              検討事項
            </p>
            <Timeline>
              {conference.topics.map((t, i) => (
                <TimelineItem
                  key={i}
                  variant="info"
                  connector={i < conference.topics.length - 1}
                >
                  <TimelineTitle className="font-normal">{t}</TimelineTitle>
                </TimelineItem>
              ))}
            </Timeline>
          </div>
          <Separator />
          <div>
            <div className="mb-2 flex items-center justify-between">
              <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                出席者
              </p>
              <Badge variant="outline">
                出席 {attendedCount} / {conference.attendees.length} 名
              </Badge>
            </div>
            <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
              {conference.attendees.map((a) => (
                <div key={a.id} className="rounded-md border border-border bg-card p-3">
                  <PersonCell
                    size="sm"
                    name={a.name}
                    secondary={a.affiliation}
                    trailing={
                      a.attended ? (
                        <Badge variant="success">出席</Badge>
                      ) : (
                        <Badge variant="outline">欠席</Badge>
                      )
                    }
                  />
                </div>
              ))}
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

// ───────────────────────── 交付・同意 (SignedRecord) ─────────────────────────

function Finalize({ plan }: { plan: CarePlan }) {
  const [record, setRecord] = React.useState<SignedRecordValue>(() => ({
    status: plan.consent.status,
    signedBy: plan.consent.signedBy,
    signedAt: plan.consent.signedAt,
    addenda: [],
  }));

  // 確定可能か：すべての短期目標にサービスが紐づいているか（簡易チェック）
  const allServicesPlanned =
    plan.needs.length > 0 && plan.needs.every((n) => n.services.length > 0);

  // 交付までの承認ルート
  const steps = [
    {
      label: "計画原案の作成",
      state: "approved" as const,
      actor: plan.careManager,
    },
    {
      label: "サービス担当者会議での検討",
      state: plan.conference.date ? ("approved" as const) : ("pending" as const),
      actor: plan.conference.date ? `${formatJpDate(plan.conference.date)} 開催` : undefined,
    },
    {
      label: "利用者・家族への説明と同意",
      state:
        record.status === "signed"
          ? ("approved" as const)
          : ("current" as const),
      actor: record.status === "signed" ? record.signedBy : "同意待ち",
      timestamp:
        record.status === "signed" && record.signedAt
          ? formatJpDate(record.signedAt)
          : undefined,
    },
    {
      label: "ケアプランの交付",
      state:
        record.status === "signed" ? ("approved" as const) : ("pending" as const),
    },
  ];

  return (
    <div className="flex flex-col gap-6">
      <Card>
        <CardHeader>
          <CardTitle as="h3">交付までの流れ</CardTitle>
          <CardDescription>
            原案作成 → 担当者会議 → 利用者同意 → 交付。確定後は内容を変更できません（修正は別記録）。
          </CardDescription>
        </CardHeader>
        <CardContent>
          <ApprovalSteps
            steps={steps}
            stateLabels={{
              approved: "完了",
              current: "対応中",
              pending: "未着手",
            }}
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle as="h3">ケアプランの確定・利用者同意・交付</CardTitle>
