export function CarePlanClient() {
  const [openId, setOpenId] = React.useState<string | null>(null);
  const selected = openId ? plans.find((p) => p.id === openId) ?? null : null;

  // サマリ集計
  const total = plans.length;
  const drafting = plans.filter((p) => p.status === "作成中").length;
  const needsRenewal = plans.filter((p) => p.status === "要更新").length;
  const certSoon = plans.filter((p) => daysUntil(p.certExpiry) <= 45).length;
  const monitoringDue = plans.filter((p) => daysUntil(p.nextMonitoring) <= 3).length;

  if (selected) {
    return <PlanDetail plan={selected} onBack={() => setOpenId(null)} />;
  }

  return (
    <div className="flex flex-col gap-6">
      {/* サマリ指標 */}
      <section aria-label="担当利用者のサマリ">
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
