          <Statistic label="作成中" value={drafting} hint="件" tone="neutral" />
          <Statistic
            label="今月の更新期限"
            value={needsRenewal}
            change="要対応"
            trend="up"
            tone="negative"
            hint="要更新"
          />
          <Statistic
            label="認定更新間近"
            value={certSoon}
            change="45日以内"
            trend="down"
            tone="negative"
            hint=""
          />
          <Statistic
            label="モニタリング未実施"
            value={monitoringDue}
            change="3日以内/超過"
            trend="up"
            tone="negative"
            hint=""
          />
        </div>
      </section>

      {/* 一覧 */}
      <Card>
        <CardHeader>
          <CardTitle as="h2" className="flex items-center gap-2 text-lg">
            <IconUsers className="h-5 w-5 text-muted-foreground" aria-hidden />
