        </CardHeader>
        <CardContent>
          <CaseloadTable onOpen={setOpenId} />
        </CardContent>
      </Card>

      {/* 注意喚起 */}
      {monitoringDue > 0 || needsRenewal > 0 ? (
        <Card>
          <CardContent className="flex items-start gap-3 p-4">
            <span className="mt-0.5 flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-warning-subtle text-warning-subtle-foreground">
