/** ISO日付（YYYY-MM-DD）の残日数 */
export function daysUntil(iso: string, base = new Date("2026-06-26")): number {
  const d = new Date(iso);
  return Math.round((d.getTime() - base.getTime()) / 86_400_000);
}

export function formatJpDate(iso: string): string {
  const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(iso);
  if (!m) return iso;
  return `${m[1]}/${m[2]}/${m[3]}`;
}

